var input = $input.first().json;
var services = input.services || [];
var customer = input.customer || {};
var totals = input.totals || {};
var booking_id = 'BK-' + new Date().getTime();
var errors = [];

if (!customer.name || customer.name.length < 2) errors.push('MISSING_NAME');
if (!customer.email || !customer.email.includes('@')) errors.push('INVALID_EMAIL');
if (!customer.phone || customer.phone.replace(/\D/g,'').length < 10) errors.push('INVALID_PHONE');
if (!input.pickup_time) errors.push('MISSING_TIME');
if (!services || services.length === 0) errors.push('EMPTY_CART');

var out = {
  json: {
    booking_id: booking_id,
    customer: customer,
    services: services,
    totals: totals,
    pickup_time: input.pickup_time,
    special_instructions: input.special_instructions || '',
    source: input.source || 'web',
    errors: errors,
    valid: errors.length === 0
  }
};

return [out];

var input = $input.first().json;
var services = input.services || [];
var line_items = [];
var subtotal = 0;

for (var i = 0; i < services.length; i++) {
  var svc = services[i];
  var price = Math.round(parseFloat(svc.price) * 100);
  var qty = svc.qty || 1;
  var item_total = price * qty;
  subtotal += item_total;
  line_items.push({
    price_data: {
      currency: 'usd',
      product_data: { name: svc.name },
      unit_amount: price
    },
    quantity: qty
  });
}

var tax_rate = 0.095;
var tax_cents = Math.round(subtotal * tax_rate);
var total_cents = subtotal + tax_cents;

// Add tax as separate line item
line_items.push({
  price_data: {
    currency: 'usd',
    product_data: { name: 'Sales Tax (9.5%)' },
    unit_amount: tax_cents
  },
  quantity: 1
});

var checkout_payload = {
  payment_method_types: ['card'],
  line_items: line_items,
  mode: 'payment',
  success_url: 'https://' + input.source + '/booking-confirmed?session_id={CHECKOUT_SESSION_ID}',
  cancel_url: 'https://' + input.source + '/booking-cancelled',
  metadata: {
    booking_id: input.booking_id,
    subtotal_cents: String(subtotal),
    tax_cents: String(tax_cents),
    tax_rate_percent: '9.5',
    source: 'systack_generic_booking'
  }
};

return [{
  json: {
    booking_id: input.booking_id,
    customer: input.customer,
    subtotal_cents: subtotal,
    tax_cents: tax_cents,
    total_cents: total_cents,
    checkout_payload: checkout_payload
  }
}];

var input = $input.first().json;
var orig = $input.all()[0].json;
return [{
  json: {
    booking_id: orig.booking_id,
    customer: orig.customer,
    payment_link: input.url || input.payment_link || '',
    total_cents: orig.total_cents,
    status: input.url ? 'payment_pending' : 'error'
  }
}];
